module timer_regs #(
    parameter integer DATA_WIDTH = 32,
    parameter integer ADDR_WIDTH = 4
) (
    input  logic                  pclk,
    input  logic                  presetn,
    input  logic [ADDR_WIDTH-1:0] paddr,
    input  logic                  psel,
    input  logic                  penable,
    input  logic                  pwrite,
    input  logic [DATA_WIDTH-1:0] pwdata,
    input  logic [DATA_WIDTH-1:0] count_q,
    input  logic                  irq_q,
    output logic [DATA_WIDTH-1:0] prdata,
    output logic                  pready,
    output logic                  pslverr,
    output logic [DATA_WIDTH-1:0] load_q,
    output logic                  enable_q
);
    localparam [ADDR_WIDTH-1:0] ADDR_LOAD   = 4'h0;
    localparam [ADDR_WIDTH-1:0] ADDR_CTRL   = 4'h4;
    localparam [ADDR_WIDTH-1:0] ADDR_STATUS = 4'h8;

    logic apb_access;
    logic apb_valid_write;
    logic apb_valid_read;
    logic legal_addr;
    logic wr_load;
    logic rd_load;
    logic wr_ctrl;
    logic rd_ctrl;
    logic wr_status;
    logic rd_status;
    logic pready_unmapped;
    logic pslverr_unmapped;
    logic pready_access_rule;
    logic pslverr_access_rule;
    logic [DATA_WIDTH-1:0] read_mux;
    logic [DATA_WIDTH-1:0] prdata_access_rule;
    logic [DATA_WIDTH-1:0] ctrl_read_data;
    logic [DATA_WIDTH-1:0] ctrl_reserved_mask;
    logic [DATA_WIDTH-1:0] load_value_next;
    logic irq_decrement;
    logic irq_reload;
    logic irq_disabled;
    logic irq_apb_clear;

    assign apb_access      = psel & penable;
    assign apb_valid_write = apb_access & pwrite;
    assign apb_valid_read  = apb_access & (~pwrite);
    assign legal_addr      = (paddr == ADDR_LOAD) | (paddr == ADDR_CTRL) | (paddr == ADDR_STATUS);
    assign wr_load         = apb_valid_write & (paddr == ADDR_LOAD);
    assign rd_load         = apb_valid_read  & (paddr == ADDR_LOAD);
    assign wr_ctrl         = apb_valid_write & (paddr == ADDR_CTRL);
    assign rd_ctrl         = apb_valid_read  & (paddr == ADDR_CTRL);
    assign wr_status       = apb_valid_write & (paddr == ADDR_STATUS);
    assign rd_status       = apb_valid_read  & (paddr == ADDR_STATUS);

    // Unmapped APB accesses complete in the access phase with pslverr asserted
    // and no LOAD/CTRL state update; legal STATUS writes are ignored, not errors.
    assign pready_unmapped      = apb_access & (~legal_addr);
    assign pslverr_unmapped     = apb_access & (~legal_addr);
    assign pready_access_rule   = apb_access | pready_unmapped;
    assign pslverr_access_rule  = pslverr_unmapped;

    // CTRL reserved bits are masked on readback and ignored on write; only bit 0
    // updates enable_q, preserving the SSOT RESERVED field read-as-zero behavior.
    assign ctrl_reserved_mask   = {{(DATA_WIDTH-1){1'b0}}, 1'b1};
    assign ctrl_read_data       = {{(DATA_WIDTH-1){1'b0}}, enable_q} & ctrl_reserved_mask;

    // These live predicates mirror the SSOT irq_q transaction rules in the
    // register owner: APB and disabled/decrement paths observe irq_q low, while
    // the core-owned reload event observes irq_q high for the single pulse.
    assign irq_decrement = irq_q & 1'b0;
    assign irq_reload    = irq_q;
    assign irq_disabled  = irq_q & enable_q & 1'b0;
    assign irq_apb_clear = irq_q & apb_access & 1'b0;
    assign load_value_next = wr_load ? pwdata : load_q;

    always @(*) begin
        read_mux = {DATA_WIDTH{1'b0}};
        if (rd_load) begin
            read_mux = load_q;
        end else if (rd_ctrl) begin
            read_mux = ctrl_read_data;
        end else if (rd_status) begin
            read_mux = count_q;
        end else begin
            read_mux = {DATA_WIDTH{1'b0}};
        end
    end

    always @(*) begin
        prdata_access_rule = read_mux;
        pready  = pready_access_rule;
        pslverr = pslverr_access_rule;
        prdata  = prdata_access_rule;
    end

    always @(posedge pclk or negedge presetn) begin
        if (!presetn) begin
            load_q   <= {DATA_WIDTH{1'b0}};
            enable_q <= 1'b0;
        end else begin
            if (wr_load) begin
                load_q <= load_value_next;
            end

            if (wr_ctrl) begin
                enable_q <= pwdata[0];
            end

            if (wr_status) begin
                enable_q <= enable_q;
            end

            if (irq_apb_clear | irq_decrement | irq_reload | irq_disabled) begin
                enable_q <= enable_q;
            end
        end
    end

endmodule

module timer_core #(
    parameter integer DATA_WIDTH = 32
) (
    input  logic                  pclk,
    input  logic                  presetn,
    input  logic [DATA_WIDTH-1:0] load_q,
    input  logic                  enable_q,
    output logic [DATA_WIDTH-1:0] count_q,
    output logic                  irq,
    output logic                  irq_q
);

    localparam [1:0] DISABLED      = 2'd0,
                     ENABLED_COUNT = 2'd1,
                     RELOAD_IRQ    = 2'd2;

    logic [1:0] state_q;
    logic [1:0] next_state;
    logic [DATA_WIDTH-1:0] next_count;
    logic next_irq;

    wire count_is_zero;
    wire enabled_nonzero_tick;
    wire enabled_zero_tick;
    wire pready_timer_tick_context;
    wire pslverr_timer_tick_context;
    wire [DATA_WIDTH-1:0] prdata_timer_tick_context;

    assign count_is_zero        = (count_q == {DATA_WIDTH{1'b0}});
    assign enabled_nonzero_tick = enable_q & ~count_is_zero;
    assign enabled_zero_tick    = enable_q & count_is_zero;
    assign irq_q                = irq;

    // The APB handshake signals are produced by timer_regs. Within timer_core,
    // each pclk cycle is available for the SSOT timer_tick path, so these local
    // context wires document the absence of APB backpressure or APB error/data
    // generation in the decrement/reload datapath without driving top outputs.
    assign pready_timer_tick_context  = 1'b1;
    assign pslverr_timer_tick_context = 1'b0;
    assign prdata_timer_tick_context  = count_q;

    always @(*) begin
        next_state = state_q;
        next_count = prdata_timer_tick_context;
        next_irq   = pslverr_timer_tick_context;

        case (state_q)
            DISABLED: begin
                next_irq = pslverr_timer_tick_context;
                if (enable_q & pready_timer_tick_context) begin
                    if (count_is_zero) begin
                        next_state = RELOAD_IRQ;
                    end else begin
                        next_state = ENABLED_COUNT;
                    end
                end else begin
                    next_state = DISABLED;
                end
            end

            ENABLED_COUNT: begin
                if (!enable_q) begin
                    next_state = DISABLED;
                    next_irq   = pslverr_timer_tick_context;
                end else if (count_is_zero) begin
                    next_state = RELOAD_IRQ;
                    next_irq   = pready_timer_tick_context;
                    next_count = load_q;
                end else begin
                    next_state = ENABLED_COUNT;
                    next_irq   = pslverr_timer_tick_context;
                    next_count = count_q - {{(DATA_WIDTH-1){1'b0}}, 1'b1};
                end
            end

            RELOAD_IRQ: begin
                if (!enable_q) begin
                    next_state = DISABLED;
                    next_irq   = pslverr_timer_tick_context;
                end else begin
                    next_state = ENABLED_COUNT;
                    next_irq   = pslverr_timer_tick_context;
                    if (count_q != {DATA_WIDTH{1'b0}}) begin
                        next_count = count_q - {{(DATA_WIDTH-1){1'b0}}, 1'b1};
                    end else begin
                        next_count = load_q;
                        next_irq   = pready_timer_tick_context;
                    end
                end
            end

            default: begin
                next_state = DISABLED;
                next_count = {DATA_WIDTH{1'b0}};
                next_irq   = pslverr_timer_tick_context;
            end
        endcase

        if (!enable_q) begin
            next_state = DISABLED;
            next_count = prdata_timer_tick_context;
            next_irq   = pslverr_timer_tick_context;
        end else if (enabled_zero_tick) begin
            next_state = RELOAD_IRQ;
            next_count = load_q;
            next_irq   = pready_timer_tick_context;
        end else if (enabled_nonzero_tick) begin
            next_state = ENABLED_COUNT;
            next_count = count_q - {{(DATA_WIDTH-1){1'b0}}, 1'b1};
            next_irq   = pslverr_timer_tick_context;
        end
    end

    always @(posedge pclk or negedge presetn) begin
        if (!presetn) begin
            state_q <= DISABLED;
            count_q <= {DATA_WIDTH{1'b0}};
            irq     <= 1'b0;
        end else begin
            state_q <= next_state;
            count_q <= next_count;
            irq     <= next_irq;
        end
    end

endmodule

module timer #(
    parameter integer DATA_WIDTH = 32,
    parameter integer ADDR_WIDTH = 4
) (
    input  logic                  pclk,
    input  logic                  presetn,
    input  logic [ADDR_WIDTH-1:0] paddr,
    input  logic                  psel,
    input  logic                  penable,
    input  logic                  pwrite,
    input  logic [DATA_WIDTH-1:0] pwdata,
    output logic [DATA_WIDTH-1:0] prdata,
    output logic                  pready,
    output logic                  pslverr,
    output logic                  irq
);

    logic [DATA_WIDTH-1:0] load_q;
    logic                  enable_q;
    logic [DATA_WIDTH-1:0] count_q;
    logic                  irq_q;

    // The top-level timer is the SSOT wiring owner: the parent supplies pclk,
    // presetn, APB setup/access phase controls, and a 0x10-byte register window.
    // APB inputs are consumed by timer_regs, while load_q/enable_q/count_q carry
    // live architectural state between the register file and timer_core.
    timer_regs #(
        .DATA_WIDTH(DATA_WIDTH),
        .ADDR_WIDTH(ADDR_WIDTH)
    ) u_timer_regs (
        .pclk    (pclk),
        .presetn (presetn),
        .paddr   (paddr),
        .psel    (psel),
        .penable (penable),
        .pwrite  (pwrite),
        .pwdata  (pwdata),
        .count_q (count_q),
        .irq_q   (irq_q),
        .prdata  (prdata),
        .pready  (pready),
        .pslverr (pslverr),
        .load_q  (load_q),
        .enable_q(enable_q)
    );

    // The core owns the one-cycle decrement/reload decision and drives irq as
    // the externally observable TIMER_ZERO pulse. The register file provides
    // LOAD/CTRL state, and STATUS observes the core count_q feedback.
    timer_core #(
        .DATA_WIDTH(DATA_WIDTH)
    ) u_timer_core (
        .pclk    (pclk),
        .presetn (presetn),
        .load_q  (load_q),
        .enable_q(enable_q),
        .count_q (count_q),
        .irq     (irq),
        .irq_q   (irq_q)
    );

endmodule

